export default function BookPage({ page, pageNum, total, onShowRef, pageW, pageH }) {
  const isCover = page.type === "cover";
  const isEnd   = page.type === "end";

  const scale = Math.min(pageW / 380, pageH / 500, 1.6);
  const em = (base) => Math.round(base * scale);

  const s = page.style || {};

  // ─── fonts & alignment ────────────────────────────────────────────────────
  const fontFamily      = s.fontFamily      || "'Bubblegum Sans', cursive";
  const titleFontFamily = s.titleFontFamily || fontFamily;
  const textFontFamily  = s.textFontFamily  || fontFamily;
  const titleAlign      = s.titleAlign  || "center";
  const textAlign       = s.textAlign   || "center";
  const titleWeight     = s.titleWeight !== undefined ? s.titleWeight : 800;
  const titleItalic     = s.titleItalic || false;

  // ─── spacing ──────────────────────────────────────────────────────────────
  const gap      = s.gap !== undefined ? s.gap : 12;
  const [pV, pH] = s.padding || [24, 20];

  // ─── single-image defaults ────────────────────────────────────────────────
  const imageW      = s.imageW;
  const imageH      = s.imageH;
  const imageFit    = s.imageFit;
  const imagePos    = s.imagePosition;
  const imageRadius = s.imageRadius;
  const imageBorder = s.imageBorder;
  const imageShadow = s.imageShadow || "0 4px 12px rgba(0,0,0,0.15)";
  const imageMaxW   = s.imageMaxW;

  // ─── multi-image row defaults (imagesStyle) ───────────────────────────────
  // imagesStyle controls the flex container that wraps multiple images.
  // Each item in the page.images array can also carry its own overrides.
  const ms                  = s.imagesStyle || {};
  const imagesRowGap        = ms.gap        !== undefined ? ms.gap        : 8;
  const imagesDirection     = ms.direction  || "row";          // "row" | "column"
  const imagesAlign         = ms.align      || "center";       // align-items
  const imagesJustify       = ms.justify    || "center";       // justify-content
  const imagesWrap          = ms.wrap       || "nowrap";       // flex-wrap
  const imagesContainerW    = ms.containerW || "100%";
  const imagesContainerH    = ms.containerH || undefined;
  // per-image fallback sizing when the item itself has no override
  const imagesDefaultW      = ms.itemW      || "auto";
  const imagesDefaultH      = ms.itemH      || "auto";
  const imagesDefaultFit    = ms.itemFit    || "contain";
  const imagesDefaultRadius = ms.itemRadius !== undefined ? ms.itemRadius : 8;
  const imagesDefaultBorder = ms.itemBorder || "none";
  const imagesDefaultShadow = ms.itemShadow || "0 4px 12px rgba(0,0,0,0.15)";
  const imagesDefaultFlex   = ms.itemFlex   || "1 1 0";        // each image's flex value

  // ─── text card ────────────────────────────────────────────────────────────
  const cardBg     = s.cardBg    || "rgba(255,255,255,0.28)";
  const cardRadius = s.cardRadius !== undefined ? s.cardRadius : 18;
  const cardBorder = s.cardBorder || "none";
  const [cV, cH]   = s.cardPadding || [14, 18];

  // ─── facts panel container ────────────────────────────────────────────────
  const factsBg     = s.factsBg    || "rgba(255,255,255,0.25)";
  const factsRadius = s.factsRadius !== undefined ? s.factsRadius : 14;
  const factsBorder = s.factsBorder || "none";

  // ─── facts TEXT styling ───────────────────────────────────────────────────
  const factsFontFamily = s.factsFontFamily || textFontFamily;
  const factsFontSize   = s.factsFontSize   !== undefined ? s.factsFontSize   : 12;
  const factsColor      = s.factsColor      || page.textColor || "#333";
  const factsFontWeight = s.factsFontWeight !== undefined ? s.factsFontWeight : 400;
  const factsFontStyle  = s.factsFontStyle  || "normal";
  const factsLineHeight = s.factsLineHeight !== undefined ? s.factsLineHeight : 1.55;
  const factsTextAlign  = s.factsTextAlign  || "left";

  // ─── facts AUTHOR styling ─────────────────────────────────────────────────
  const factsAuthorFontFamily = s.factsAuthorFontFamily || titleFontFamily;
  const factsAuthorFontSize   = s.factsAuthorFontSize   !== undefined ? s.factsAuthorFontSize   : 12;
  const factsAuthorColor      = s.factsAuthorColor      || factsColor;
  const factsAuthorFontWeight = s.factsAuthorFontWeight !== undefined ? s.factsAuthorFontWeight : 700;
  const factsAuthorFontStyle  = s.factsAuthorFontStyle  || "italic";
  const factsAuthorAlign      = s.factsAuthorAlign      || factsTextAlign;

  // ─── page chrome ──────────────────────────────────────────────────────────
  const pageBorder     = s.pageBorder     || "none";
  const overlayCircles = s.overlayCircles !== false;

  // ─── content order ────────────────────────────────────────────────────────
  const defaultOrder = ["image", "title", "subtitle", "text", "facts", "emoji"];
  const contentOrder = s.contentOrder || defaultOrder;

  // ─── helper: render one <img> ─────────────────────────────────────────────
  const renderImg = ({ src, alt, w, h, fit, pos, radius, border, shadow, maxW, flex, style: extra = {} }) => {
    const filterVal = shadow
      ? shadow.split(",").map(sh => `drop-shadow(${sh.trim()})`).join(" ")
      : "none";
    return (
      <img
        src={src}
        alt={alt || ""}
        style={{
          width: w,
          height: h,
          maxWidth: maxW,
          objectFit: fit,
          objectPosition: pos || "center",
          borderRadius: typeof radius === "number" ? em(radius) : radius,
          border: border || "none",
          filter: filterVal,
          flex: flex,
          flexShrink: 0,
          display: "block",
          minWidth: 0,
          ...extra,
        }}
      />
    );
  };

  // ─── block renderers ──────────────────────────────────────────────────────
  const blocks = {

    // IMAGE — handles both single (page.image) and multiple (page.images)
    image: (() => {
      // ── MULTI-IMAGE: page.images array ──
      if (Array.isArray(page.images) && page.images.length > 0) {
        return (
          <div
            key="image"
            style={{
              display: "flex",
              flexDirection: imagesDirection,
              alignItems: imagesAlign,
              justifyContent: imagesJustify,
              flexWrap: imagesWrap,
              gap: em(imagesRowGap),
              width: imagesContainerW,
              height: imagesContainerH,
              flexShrink: 0,
              boxSizing: "border-box",
            }}
          >
            {page.images.map((img, idx) => {
              // Each item: string URL  OR  { src, w, h, fit, radius, border, shadow, flex, caption }
              const isStr = typeof img === "string";
              const src     = isStr ? img : img.src;
              const w       = isStr ? imagesDefaultW      : (img.w       ?? imagesDefaultW);
              const h       = isStr ? imagesDefaultH      : (img.h       ?? imagesDefaultH);
              const fit     = isStr ? imagesDefaultFit    : (img.fit     ?? imagesDefaultFit);
              const pos     = isStr ? "center"            : (img.position ?? "center");
              const radius  = isStr ? imagesDefaultRadius : (img.radius  ?? imagesDefaultRadius);
              const border  = isStr ? imagesDefaultBorder : (img.border  ?? imagesDefaultBorder);
              const shadow  = isStr ? imagesDefaultShadow : (img.shadow  ?? imagesDefaultShadow);
              const flex    = isStr ? imagesDefaultFlex   : (img.flex    ?? imagesDefaultFlex);
              const caption = isStr ? null                : img.caption;

              return (
                <div
                  key={idx}
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    gap: em(4),
                    flex: flex,
                    minWidth: 0,
                  }}
                >
                  {renderImg({ src, alt: caption || page.title, w, h, fit, pos, radius, border, shadow })}
                  {caption && (
                    <span
                      style={{
                        fontFamily: textFontFamily,
                        fontSize: em(10),
                        opacity: 0.75,
                        textAlign: "center",
                        lineHeight: 1.3,
                      }}
                    >
                      {caption}
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        );
      }

      // ── SINGLE IMAGE: page.image string ──
      if (page.image) {
        return renderImg({
          key: "image",
          src: page.image,
          alt: page.title,
          w: imageW,
          h: imageH,
          fit: imageFit,
          pos: imagePos,
          radius: imageRadius,
          border: imageBorder,
          shadow: imageShadow,
          maxW: imageMaxW,
          style: { alignSelf: "center" },
        });
      }

      // ── FALLBACK emoji ──
      return (
        <div
          key="image"
          style={{ fontSize: em(isCover || isEnd ? 88 : 68), lineHeight: 1, flexShrink: 0 }}
        >
          {page.emoji || "📖"}
        </div>
      );
    })(),

    // TITLE
    title: (
      <div
        key="title"
        style={{
          fontFamily: titleFontFamily,
          fontSize: em(page.titleSize || (isCover || isEnd ? page.fontSize || 32 : 24)),
          fontWeight: titleWeight,
          fontStyle: titleItalic ? "italic" : "normal",
          textAlign: titleAlign,
          lineHeight: 1.2,
          textShadow: "0 2px 10px rgba(0,0,0,0.18)",
          letterSpacing: isCover ? "0.04em" : "0.01em",
          width: "100%",
          flexShrink: 0,
        }}
      >
        {page.title}
      </div>
    ),

    // SUBTITLE
    subtitle: page.subtitle ? (
      <div
        key="subtitle"
        style={{
          fontFamily,
          fontSize: em(17),
          opacity: 0.92,
          textAlign: titleAlign,
          fontStyle: "italic",
          width: "100%",
          flexShrink: 0,
        }}
      >
        {page.subtitle}
      </div>
    ) : null,

    // BODY TEXT CARD
    text: page.text ? (
      <div
        key="text"
        style={{
          fontFamily: textFontFamily,
          fontSize: em(page.fontSize || 17),
          textAlign,
          lineHeight: 1.7,
          maxWidth: em(320),
          width: "100%",
          background: cardBg,
          borderRadius: em(cardRadius),
          border: cardBorder,
          padding: `${em(cV)}px ${em(cH)}px`,
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          flexShrink: 0,
        }}
      >
        {page.text}
      </div>
    ) : null,

    // FACTS PANEL
    facts: page.reference?.facts?.length > 0 ? (
      <div
        key="facts"
        style={{
          background: factsBg,
          borderRadius: em(factsRadius),
          border: factsBorder,
          padding: `${em(8)}px ${em(10)}px`,
          width: "98%",
          maxWidth: "98%",
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          flexShrink: 0,
        }}
      >
        <ul style={{ margin: 0, paddingLeft: em(18), listStyle: "disc" }}>
          {page.reference.facts.map((fact, i) => (
            <li
              key={i}
              style={{
                fontFamily: factsFontFamily,
                fontSize: em(factsFontSize),
                color: factsColor,
                fontWeight: factsFontWeight,
                fontStyle: factsFontStyle,
                lineHeight: factsLineHeight,
                textAlign: factsTextAlign,
                marginBottom: em(4),
              }}
            >
              {fact}
            </li>
          ))}
        </ul>

        {page.reference.author && (
          <div
            style={{
              fontFamily: factsAuthorFontFamily,
              fontSize: em(factsAuthorFontSize),
              color: factsAuthorColor,
              fontWeight: factsAuthorFontWeight,
              fontStyle: factsAuthorFontStyle,
              textAlign: factsAuthorAlign,
              marginTop: em(6),
              paddingTop: em(4),
              borderTop: `1px solid ${factsAuthorColor}33`,
              width: "100%",
              boxSizing: "border-box",
            }}
          >
            {page.reference.author}
          </div>
        )}
      </div>
    ) : null,

    // EMOJI
    emoji: page.emoji ? (
      <div key="emoji" style={{ fontSize: em(40), flexShrink: 0 }}>
        {page.emoji}
      </div>
    ) : null,
  };

  // ─── render ───────────────────────────────────────────────────────────────
  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        background: page.bg || "#fff",
        color: page.textColor || "#333",
        border: pageBorder,
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: em(gap),
        padding: `${em(pV)}px ${em(pH)}px`,
        boxSizing: "border-box",
        fontFamily,
        position: "relative",
        userSelect: "none",
      }}
    >
      {overlayCircles && (
        <>
          <div style={{
            position: "absolute", top: em(-45), left: em(-45),
            width: em(140), height: em(140), borderRadius: "50%",
            background: "rgba(255,255,255,0.13)", pointerEvents: "none",
          }} />
          <div style={{
            position: "absolute", bottom: em(-30), right: em(-30),
            width: em(100), height: em(100), borderRadius: "50%",
            background: "rgba(255,255,255,0.10)", pointerEvents: "none",
          }} />
        </>
      )}

      {contentOrder.map((token) => blocks[token] ?? null)}

      {!isCover && (
        <div style={{
          position: "absolute", bottom: em(8),
          fontSize: em(11), opacity: 0.5,
          fontFamily: "'Nunito', sans-serif",
        }}>
          {pageNum} / {total - 1}
        </div>
      )}
    </div>
  );
}
